/// <summary>
/// Converts a string to camelCase.
/// </summary>
/// <param name="input">The string to convert.</param>
/// <returns>A camelCase representation of the input string.</returns>
/// <example>
/// <code>
/// "SomePropertyName".Camelize() => "somePropertyName"
/// "some_property_name".Camelize() => "somePropertyName"
/// </code>
/// </example>
public static string Camelize(this string input)
{
    var regex = WordPartsRegex();
    var sb = new StringBuilder(input.Length);
    var isFirst = true;
    foreach (Match match in regex.Matches(input))
    {
        var span = match.ValueSpan;
        if (isFirst)
        {
            sb.Append(char.ToLowerInvariant(span[0]));
            isFirst = false;
        }
        else
        {
            sb.Append(char.ToUpperInvariant(span[0]));
        }

        if (span.Length > 1)
        {
            sb.Append(span.Slice(1));
        }
    }

    return sb.ToString();
}

