/// <summary>
/// Converts a PascalCase or camelCase string to snake_case.
/// </summary>
/// <param name="input">The string to convert.</param>
/// <returns>A snake_case representation of the input string.</returns>
/// <example>
/// <code>
/// "SomePropertyName".Underscore() => "some_property_name"
/// "HTMLParser".Underscore() => "html_parser"
/// </code>
/// </example>
public static string Underscore(this string input)
{
    if (string.IsNullOrEmpty(input))
    {
        return input;
    }

    // Single-pass: walk through chars, insert '_' at case boundaries
    var sb = new StringBuilder(input.Length + 4);
    for (var i = 0; i < input.Length; i++)
    {
        var c = input[i];

        if (c == '-' || c == ' ')
        {
            sb.Append('_');
            continue;
        }

        if (i > 0 && char.IsUpper(c))
        {
            var prev = input[i - 1];
            // lower-to-upper boundary: "aB" => "a_b"
            if (char.IsLower(prev) || char.IsDigit(prev))
            {
                sb.Append('_');
            }
            // upper-to-upper-to-lower boundary: "ABc" => "A_Bc" (handles acronyms)
            else if (char.IsUpper(prev) && i + 1 < input.Length && char.IsLower(input[i + 1]))
            {
                sb.Append('_');
            }
        }

        sb.Append(char.ToLowerInvariant(c));
    }

    return sb.ToString();
}

